// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.HashMap;
import java.util.Map;
import java.util.function.LongSupplier;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.sail.NotifyingSailConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Tests for popularity-driven background CSR builds ({@code rdf4j.lmdb.csrCache.autoWarm.*}): probe traffic alone must
 * promote a hot predicate to a background build without any configured eager list, popularity must survive commits so
 * entries are rebuilt without further queries, the configurable initial score must fast-track new predicates, and the
 * kill switch must restore probe-only behavior.
 */
public class LmdbCsrAutoWarmTest {

	private static final String SEED = "http://example.com/seed";
	private static final String KNOWS = "http://example.com/knows";

	@TempDir
	File dataDir;

	private LmdbStore store;
	private Map<String, String> previousProperties;

	@BeforeEach
	public void setUp() {
		previousProperties = new HashMap<>();
		for (String property : new String[] { "rdf4j.lmdb.csrCache.eagerPredicates", "rdf4j.lmdb.csrCache.minProbes",
				"rdf4j.lmdb.csrCache.autoWarm.enabled", "rdf4j.lmdb.csrCache.autoWarm.minScore",
				"rdf4j.lmdb.csrCache.autoWarm.initialScore" }) {
			previousProperties.put(property, System.getProperty(property));
		}
		System.clearProperty("rdf4j.lmdb.csrCache.eagerPredicates");
		// make the adaptive inline trigger unreachable so any build observed here is a background one
		System.setProperty("rdf4j.lmdb.csrCache.minProbes", String.valueOf(Integer.MAX_VALUE));
		System.setProperty("rdf4j.lmdb.csrCache.autoWarm.minScore", "1");
		LmdbCsrAdjacencyCache.BUILDS.set(0);
		LmdbCsrAdjacencyCache.AUTO_WARM_BUILDS.set(0);
	}

	@AfterEach
	public void tearDown() {
		for (Map.Entry<String, String> entry : previousProperties.entrySet()) {
			if (entry.getValue() == null) {
				System.clearProperty(entry.getKey());
			} else {
				System.setProperty(entry.getKey(), entry.getValue());
			}
		}
		if (store != null) {
			store.shutDown();
		}
	}

	private void openStoreWithData() throws Exception {
		store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc"));
		store.init();
		ValueFactory vf = SimpleValueFactory.getInstance();
		IRI seed = vf.createIRI(SEED);
		IRI knows = vf.createIRI(KNOWS);
		try (NotifyingSailConnection connection = store.getConnection()) {
			connection.begin();
			for (int subject = 0; subject < 20; subject++) {
				IRI s = vf.createIRI("http://example.com/s" + subject);
				connection.addStatement(s, seed, vf.createIRI("http://example.com/root"));
				for (int object = 0; object < 3; object++) {
					connection.addStatement(s, knows, vf.createIRI("http://example.com/o" + (subject * 3 + object)));
				}
			}
			connection.commit();
		}
	}

	private void probeKnows() throws Exception {
		ValueFactory vf = SimpleValueFactory.getInstance();
		CsrProbeWarmupAccess.warmBySubject(store, vf.createIRI(SEED), vf.createIRI(KNOWS));
	}

	@Test
	public void popularPredicateBuildsInBackgroundAndRebuildsAfterCommit() throws Exception {
		openStoreWithData();
		assertThat(LmdbCsrAdjacencyCache.AUTO_WARM_BUILDS.get()).isZero();

		// probe traffic alone (no eager list, inline trigger unreachable) must promote the predicate
		probeKnows();
		awaitAtLeast(1, LmdbCsrAdjacencyCache.AUTO_WARM_BUILDS::get);
		assertThat(LmdbCsrAdjacencyCache.BUILDS.get()).isGreaterThanOrEqualTo(1);

		// a committed write drops all entries; the surviving popularity must drive a rebuild with no further queries
		LmdbCsrAdjacencyCache.AUTO_WARM_BUILDS.set(0);
		ValueFactory vf = SimpleValueFactory.getInstance();
		try (NotifyingSailConnection connection = store.getConnection()) {
			connection.begin();
			connection.addStatement(vf.createIRI("http://example.com/s0"), vf.createIRI(KNOWS),
					vf.createIRI("http://example.com/oExtra"));
			connection.commit();
		}
		awaitAtLeast(1, LmdbCsrAdjacencyCache.AUTO_WARM_BUILDS::get);
	}

	@Test
	public void initialScoreSeedPromotesNewPredicateImmediately() throws Exception {
		// the probe volume alone (~20) can never reach the threshold; only the configured seed can
		System.setProperty("rdf4j.lmdb.csrCache.autoWarm.minScore", "1000");
		System.setProperty("rdf4j.lmdb.csrCache.autoWarm.initialScore", "1000");
		openStoreWithData();

		probeKnows();
		awaitAtLeast(1, LmdbCsrAdjacencyCache.AUTO_WARM_BUILDS::get);
	}

	@Test
	public void autoWarmDisabledMeansNoBackgroundBuilds() throws Exception {
		System.setProperty("rdf4j.lmdb.csrCache.autoWarm.enabled", "false");
		openStoreWithData();

		probeKnows();
		Thread.sleep(1_500);
		assertThat(LmdbCsrAdjacencyCache.AUTO_WARM_BUILDS.get()).isZero();
		assertThat(LmdbCsrAdjacencyCache.BUILDS.get())
				.as("with auto-warm off and no eager list, no background build may fire")
				.isZero();
	}

	private static void awaitAtLeast(long expected, LongSupplier actual) throws InterruptedException {
		long deadline = System.nanoTime() + 15_000_000_000L;
		while (actual.getAsLong() < expected && System.nanoTime() < deadline) {
			Thread.sleep(25);
		}
		assertThat(actual.getAsLong())
				.as("popularity-driven CSR adjacency builds within 15s")
				.isGreaterThanOrEqualTo(expected);
	}
}
